function backtrack(path, choices):
  if path is a complete solution:
    record(path)
    return
  for choice in choices:
    if not valid(path, choice):
      continue
    path.add(choice)          # choose
    backtrack(path, remaining(choices, choice))  # recurse
    path.removeLast()         # undo

