parent = [i for i in 0 .. n-1]
rank = [0] * n

function find(x):
  if parent[x] != x:
    parent[x] = find(parent[x])  # path compression
  return parent[x]

function union(x, y):
  rootX = find(x)
  rootY = find(y)
  if rootX == rootY:
    return
  if rank[rootX] < rank[rootY]:
    swap(rootX, rootY)
  parent[rootY] = rootX  # union by rank
  if rank[rootX] == rank[rootY]:
    rank[rootX] += 1

